15	type skillFrontmatter struct {
16		Name         string `yaml:"name"`
17		Description  string `yaml:"description"`
18		ArgumentHint string `yaml:"argument-hint,omitempty"`
19		Skill        any    `yaml:"skill,omitempty"`
20	}
