22	// Issue represents one skill validation problem.
23	type Issue struct {
24		Path    string
25		Message string
26	}
27	
28	func (i Issue) Error() string {
29		if i.Path == "" {
30			return i.Message
31		}
32		return fmt.Sprintf("%s: %s", i.Path, i.Message)
33	}
