35	// ValidateContent checks one SKILL.md payload against the DDx skill metadata contract.
36	func ValidateContent(name string, data []byte) []Issue {
37		frontmatter, body, ok := splitSkillFrontmatter(data)
38		if !ok {
39			return []Issue{{Path: name, Message: "missing YAML frontmatter delimited by ---"}}
40		}
41	
42		var meta skillFrontmatter
43		if err := yaml.Unmarshal(frontmatter, &meta); err != nil {
44			return []Issue{{Path: name, Message: fmt.Sprintf("invalid YAML frontmatter: %v", err)}}
45		}
46	
47		var issues []Issue
48		if meta.Skill != nil {
49			issues = append(issues, Issue{Path: name, Message: "nested `skill:` frontmatter is not allowed; use top-level `name` and `description`"})
50		}
51		if strings.TrimSpace(meta.Name) == "" {
52			issues = append(issues, Issue{Path: name, Message: "missing required top-level `name` field"})
53		}
54		if strings.TrimSpace(meta.Description) == "" {
55			issues = append(issues, Issue{Path: name, Message: "missing required top-level `description` field"})
56		}
57		if strings.TrimSpace(string(body)) == "" {
58			issues = append(issues, Issue{Path: name, Message: "markdown body is empty"})
59		}
60		if strings.TrimSpace(meta.ArgumentHint) == "" && bytes.Contains(frontmatter, []byte("argument-hint:")) {
61			issues = append(issues, Issue{Path: name, Message: "`argument-hint` must not be empty when present"})
62		}
63		return issues
64	}
